import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversal {
    private static final String BASE_DIRECTORY = "/path/to/files/";

    public static void main(String[] args) throws IOException {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        File requestedFile = new File(BASE_DIRECTORY + fileName);

        if (requestedFile.getCanonicalPath().startsWith(new File(BASE_DIRECTORY).getCanonicalPath())) {
            FileInputStream fis = new FileInputStream(requestedFile);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } else {
            System.out.println("Access denied. Invalid file path.");
        }
    }
}

